import createReducer from '~/redux/store/createReducer';
import { Action } from 'redux';

export enum CardsTypes {
  REQUEST = '@cards/REQUEST',
  SUCCESS = '@cards/SUCCESS',
  FAILED = '@cards/FAILED',
  CLEAR = '@cards/CLEAR',
}

export type CardCallback = (data: {
  statusCode: number | undefined;
  response: CardsResponseData;
}) => void;

export interface CardsResponseData {
  code: number;
  message: string;
  data: {
    Cards: {
      Conta: string;
      VlLimiteCreditoDisponivel: number;
      DiaVencimento: string;
      NmPortador: string;
      NrCartao: string;
      SequenciaCartao: number;
      Bandeira: string;
      Titular: boolean;
      JwtCartao: string;
      Bloqueio: boolean;
      CodigoBloqueio: number;
      CartaoCriptografado: string;
      Virtual: boolean;
      ValidadeCartao: string;
      Logo: string;
    }[];
  };
}

export type CardsReducerData = CardsResponseData['data'];

export interface CardsReducerProps {
  isLoading: boolean;
  isError: boolean;
  data: CardsReducerData | undefined;
}

type State = CardsReducerProps;

const initialState: CardsReducerProps = {
  isLoading: false,
  isError: false,
  data: undefined,
};

const cardsReducer = createReducer(initialState, {
  [CardsTypes.REQUEST](state: State): State {
    return {
      ...state,
      isLoading: true,
    };
  },
  [CardsTypes.SUCCESS](
    state: State,
    { data }: { data: CardsReducerData },
  ): State {
    return { ...state, isLoading: false, isError: false, data };
  },
  [CardsTypes.FAILED](state: State): State {
    return {
      ...state,
      isLoading: false,
      isError: true,
    };
  },
  [CardsTypes.CLEAR](): State {
    return initialState;
  },
});

interface CardsActions {
  cardRequest: (callback: CardCallback) => Action;
  cardSuccess: (data: CardsReducerData) => Action;
  cardError: () => Action;
  cardClean: () => Action;
}

export const cardsActions: CardsActions = {
  cardRequest: callback => ({
    type: CardsTypes.REQUEST,
    callback,
  }),
  cardSuccess: (data: CardsReducerData) => ({
    type: CardsTypes.SUCCESS,
    data,
  }),
  cardError: () => ({
    type: CardsTypes.FAILED,
  }),
  cardClean: () => ({
    type: CardsTypes.CLEAR,
  }),
};

export default cardsReducer;

