import { Action } from 'redux';
import createReducer from '~/redux/store/createReducer';

export const ExemptionEligibilityTypes = {
  REQUEST_EXEMPTION_ELIGIBILITY:
    '@exemptionEligibility/REQUEST_EXEMPTION_ELIGIBILITY',
  SUCCESS_EXEMPTION_ELIGIBILITY:
    '@exemptionEligibility/SUCCESS_EXEMPTION_ELIGIBILITY',
  FAILED_EXEMPTION_ELIGIBILITY:
    '@exemptionEligibility/FAILED_EXEMPTION_ELIGIBILITY',
  CLEAN: '@exemptionEligibility/CLEAN',
};

export interface ExemptionEligibilityReducerProps {
  isLoading: boolean;
  isError: boolean;
  isEligible: boolean | undefined;
}

export interface ExemptionEligibilityResponse {
  isEligible: boolean;
}

interface ExemptionEligibilityActions {
  requestExemptionEligibility: () => Action;
  successExemptionEligibility: (response: ExemptionEligibilityResponse) => {
    type: string;
    payload: ExemptionEligibilityResponse;
  };
  failedExemptionEligibility: () => Action;
  clean: () => Action;
}

export const initialState: ExemptionEligibilityReducerProps = {
  isLoading: false,
  isError: false,
  isEligible: undefined,
};

type State = ExemptionEligibilityReducerProps;

const exemptionEligibilityReducer = createReducer(initialState, {
  [ExemptionEligibilityTypes.REQUEST_EXEMPTION_ELIGIBILITY](
    state: State,
  ): State {
    return {
      ...state,
      isLoading: true,
    };
  },
  [ExemptionEligibilityTypes.SUCCESS_EXEMPTION_ELIGIBILITY]: (
    state: State,
    action: { payload: ExemptionEligibilityResponse },
  ): State => {
    return {
      ...state,
      isLoading: false,
      isError: false,
      isEligible: action.payload.isEligible,
    };
  },
  [ExemptionEligibilityTypes.FAILED_EXEMPTION_ELIGIBILITY](
    state: State,
  ): State {
    return {
      ...state,
      isLoading: false,
      isError: true,
      isEligible: false,
    };
  },
  [ExemptionEligibilityTypes.CLEAN](state: State): State {
    return {
      ...state,
      isLoading: false,
      isError: false,
      isEligible: undefined,
    };
  },
});

export const exemptionEligibilityActions: ExemptionEligibilityActions = {
  requestExemptionEligibility: () => ({
    type: ExemptionEligibilityTypes.REQUEST_EXEMPTION_ELIGIBILITY,
  }),
  successExemptionEligibility: (response: ExemptionEligibilityResponse) => ({
    type: ExemptionEligibilityTypes.SUCCESS_EXEMPTION_ELIGIBILITY,
    payload: response,
  }),
  failedExemptionEligibility: () => ({
    type: ExemptionEligibilityTypes.FAILED_EXEMPTION_ELIGIBILITY,
  }),
  clean: () => ({
    type: ExemptionEligibilityTypes.CLEAN,
  }),
};

export default exemptionEligibilityReducer;

