  [PaymentChangeTypes.PAYMENT_CHANGE_REQUEST](state: State): State {
    return { ...state, isLoading: true, isError: false };
  },
  [PaymentChangeTypes.PAYMENT_CHANGE_SUCCESS](state: State): State {
    return { ...state, isLoading: false, isError: false };
  },
  [PaymentChangeTypes.PAYMENT_CHANGE_FAILED](state: State): State {
    return { ...state, isLoading: false, isError: true };
  },
  [PaymentChangeTypes.PAYMENT_CHANGE_CLEAN](): State {
    return initialState;
  },
});

